type EventMap = {
  login: { userId: string; username: string };
  logout: void;
  error: { code: number; message: string };
};

export class EventBus {
  private listeners: { [K in keyof EventMap]?: Array<(payload: EventMap[K]) => void> } = {};

  subscribe<K extends keyof EventMap>(event: K, callback: (payload: EventMap[K]) => void): () => void {
    if (!this.listeners[event]) {
      this.listeners[event] = [];
    }
    this.listeners[event]!.push(callback as any);
    return () => {
      this.listeners[event] = this.listeners[event]!.filter(cb => cb !== callback) as any;
    };
  }

  publish<K extends keyof EventMap>(event: K, payload: EventMap[K]): void {
    const callbacks = this.listeners[event];
    if (callbacks) {
      callbacks.forEach(cb => cb(payload));
    }
  }
}
